const redisData = $("GET Estado Atual").item.json.propertyName
  ? JSON.parse($("GET Estado Atual").item.json.propertyName)
  : {};
const currentStageId = redisData.stage_id || "START";
const vars = redisData.vars || {};
const stageConfig = workflow[currentStageId] || workflow["START"];

// --- VARREDURA GLOBAL DE VARIÁVEIS ---
let missingVars = [];
for (const key in workflow) {
  const step = workflow[key];
  if (step.type === "input" && step.variables) {
    step.variables.forEach((v) => {
      if (!vars[v.name] || vars[v.name].value === null || vars[v.name].value === 'invalid_option' || vars[v.name].value === 'not_provided' || vars[v.name].value === 'answer_later') {
        missingVars.push({
          name: v.name,
          description: v.description,
          options: v.options || null,
        });
      }
    });
  }
}

return {
  workflow,
  currentStageId,
  stageConfig,
  vars,
  missingVars,
  userMsg: $("CONCATENA1").item.json.user_full_message,
  missingVar: JSON.parse($input.first().json.propertyName)?.missingVar,
};

